{"code":"import json, math
# Load stockinfo file
with open(var_call_gS4FSnUcnhKgrZzAmEzsMtuc, 'r') as f:
    stockinfo = json.load(f)
mapping = {rec['Symbol']: rec.get('Company Description','') for rec in stockinfo}

# Collect query_db results from globals
rows = []
for k,v in globals().items():
    if k.startswith('var_call_'):
        try:
            # v can be list/dict/string
            if isinstance(v, list):
                for rec in v:
                    if isinstance(rec, dict) and 'symbol' in rec:
                        rows.append(rec)
        except Exception:
            pass

# Process rows
processed = []
for r in rows:
    sym = r.get('symbol')
    up = r.get('up_count')
    down = r.get('down_count')
    try:
        upf = float(up)
        downf = float(down)
    except Exception:
        continue
    if math.isnan(upf) or math.isnan(downf):
        continue
    processed.append({'symbol': sym, 'up': upf, 'down': downf})

# Filter where up > down
filtered = [p for p in processed if p['up'] > p['down']]
# Sort by up desc
filtered.sort(key=lambda x: x['up'], reverse=True)
# Take top 5
top5 = filtered[:5]
# Map to company description (name)
result_names = [mapping.get(p['symbol'], p['symbol']) for p in top5]

print('__RESULT__:')
print(json.dumps(result_names))"}
